const apiKey = process.env.WAVESPEED_API_KEY || '';
const baseUrl = 'https://api.wavespeed.ai/api/v3';

const input = $input.first().json;
const imageUrl = input.image_url || '';
const prompt = input.prompt || '';

if (!imageUrl) {
  throw new Error('image_url is required');
}

// Submit video generation task
const submitBody = {
  inputs: {
    image: imageUrl,
    duration: 10
  },
  enable_safety_checker: true
};

if (prompt) {
  submitBody.inputs.prompt = prompt;
}

const submitRes = await fetch(`${baseUrl}/wavespeed-ai/wan-i2v-720p`, {
  method: 'POST',
  headers: {
    'Authorization': `Bearer ${apiKey}`,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(submitBody)
});

const submitData = await submitRes.json();
if (!submitData.data || !submitData.data.id) {
  throw new Error(`Failed to submit video task: ${JSON.stringify(submitData)}`);
}

const taskId = submitData.data.id;

// Poll every 10 seconds, max 20 attempts (200 seconds)
let videoUrl = null;
let finalStatus = 'timeout';

for (let attempt = 0; attempt < 20; attempt++) {
  await new Promise(r => setTimeout(r, 10000));
  const pollRes = await fetch(`${baseUrl}/predictions/${taskId}`, {
    headers: { 'Authorization': `Bearer ${apiKey}` }
  });
  const pollData = await pollRes.json();
  const status = pollData.data?.status;
  if (status === 'succeeded') {
    videoUrl = (pollData.data.outputs && pollData.data.outputs[0]) || null;
    finalStatus = 'succeeded';
    break;
  }
  if (status === 'failed') {
    finalStatus = 'failed';
    break;
  }
}

return [{ json: { video_url: videoUrl, image_url: imageUrl, status: finalStatus } }];
